#include <iostream>
#include <algorithm>
using namespace std;
struct student
{
    string name;
    int age;
    int num;
};
int main()
{
    int n;
    cin>>n;
    student a[10];
    for(int i=0;i<=n-1;i++)
    {
        cin>>a[i].name>>a[i].age>>a[i].num;
    }
    for(int i=0;i<=n-1;i++)
    {
        a[i].age++;
        a[i].num*=1.2;
        if(a[i].num>600)
        {
            a[i].num=600;
        }
        cout<<a[i].name<<" "<<a[i].age<<" "<<a[i].num<<endl;
    }
    return 0;
}
